async function post_child_exploitation_prevention(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    children,
    assessments,
    interventions,
    training,
    mappingRecords,
    contextualLinks,
    homeId,
    periodStart,
    periodEnd,
    totalStaff,
  } = body as {
    children?: { id: string; name: string }[];
    assessments?: ExploitationRiskAssessment[];
    interventions?: ExploitationIntervention[];
    training?: ExploitationTraining[];
    mappingRecords?: MappingRecord[];
    contextualLinks?: ContextualSafeguardingLink[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
    totalStaff?: number;
  };

  if (!children || !Array.isArray(children) || children.length === 0) {
    return NextResponse.json(
      { error: "children array is required and must not be empty" },
      { status: 400 },
    );
  }
  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }
  if (totalStaff === undefined || typeof totalStaff !== "number" || totalStaff < 0) {
    return NextResponse.json(
      { error: "totalStaff must be a non-negative number" },
      { status: 400 },
    );
  }

  const result = generateExploitationPreventionAssessment(
    children,
    assessments ?? [],
    interventions ?? [],
    training ?? [],
    mappingRecords ?? [],
    contextualLinks ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
    totalStaff,
  );

  return NextResponse.json({ data: result });
}

