async function get_education(_req: NextRequest): Promise<Response> {

  try {
    const result = generateEducationIntelligence(
      education_DEMO_RECORDS,
      education_DEMO_POLICY,
      education_DEMO_TRAINING,
      "oak-house",
      "2026-01-01",
      "2026-05-20",
    );

    // Enrich child profiles with labels
    const enrichedProfiles = result.childProfiles.map((p) => ({
      ...p,
    }));

    // Enrich records summary with labels for UI
    const placementSummary = education_DEMO_RECORDS.reduce<Record<string, number>>((acc, r) => {
      const label = getPlacementLabel(r.placement);
      acc[label] = (acc[label] || 0) + 1;
      return acc;
    }, {});

    const attainmentSummary = education_DEMO_RECORDS.reduce<Record<string, number>>((acc, r) => {
      const label = getAttainmentLabel(r.attainment);
      acc[label] = (acc[label] || 0) + 1;
      return acc;
    }, {});

    return NextResponse.json({
      data: {
        ...result,
        childProfiles: enrichedProfiles,
        meta: {
          placementSummary,
          attainmentSummary,
          totalRecords: education_DEMO_RECORDS.length,
          totalStaff: education_DEMO_TRAINING.length,
          demoMode: true,
        },
      },
    });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : "Internal server error";
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

