async function post_governance(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    sop,
    reg45Reports,
    policies,
    notifications,
    objectives,
    meetings,
    presenceRecords,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    sop?: StatementOfPurpose;
    reg45Reports?: Reg45Report[];
    policies?: PolicyRecord[];
    notifications?: NotificationRecord[];
    objectives?: DevelopmentObjective[];
    meetings?: StaffMeetingRecord[];
    presenceRecords?: ManagementPresence[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!sop) {
    return NextResponse.json({ error: "sop object is required" }, { status: 400 });
  }
  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }

  const result = generateGovernanceIntelligence(
    sop,
    reg45Reports ?? [],
    policies ?? [],
    notifications ?? [],
    objectives ?? [],
    meetings ?? [],
    presenceRecords ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

