async function get_mental_health_wellbeing(req: NextRequest): Promise<Response> {

  const url = new URL(req.url);
  const homeId = url.searchParams.get("homeId") ?? "home-oak";
  const now = new Date().toISOString();
  const periodStart = url.searchParams.get("periodStart") ?? "2026-01-01T00:00:00Z";
  const periodEnd = url.searchParams.get("periodEnd") ?? now;

  const assessments = mental_health_wellbeing_getDemoAssessments(homeId);
  const interventions = mental_health_wellbeing_getDemoInterventions(homeId);
  const incidents = mental_health_wellbeing_getDemoIncidents(homeId);
  const plans = mental_health_wellbeing_getDemoSafetyPlans(homeId);
  const childIds = ["child-alex", "child-jordan", "child-morgan"];

  const result = generateMentalHealthIntelligence(
    assessments,
    interventions,
    incidents,
    plans,
    childIds,
    homeId,
    periodStart,
    periodEnd,
    now,
  );

  return NextResponse.json(result);
}

