async function get_outcomes_measurement(req: NextRequest): Promise<Response> {

  try {
    const url = new URL(req.url);
    const homeId = url.searchParams.get("homeId") ?? "home-oak";

    const { baselines, measurements, targets, plans, childIds } = outcomes_measurement_getDemoData(homeId);

    const result = generateOutcomesMeasurementIntelligence(
      baselines,
      measurements,
      targets,
      plans,
      childIds,
      homeId,
      "2025-01-01",
      "2026-06-30",
      new Date().toISOString().slice(0, 10),
    );

    return NextResponse.json(result);
  } catch (error: any) {
    return NextResponse.json(
      { error: error.message || "Internal server error" },
      { status: 500 },
    );
  }
}

async function post_outcomes_measurement(req: NextRequest): Promise<Response> {

  try {
    const body = await req.json();
    const {
      baselines,
      measurements,
      targets,
      plans,
      childIds,
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    } = body;

    if (!baselines || !measurements || !childIds || !homeId) {
      return NextResponse.json(
        { error: "Required: baselines, measurements, childIds, homeId" },
        { status: 400 },
      );
    }

    const result = generateOutcomesMeasurementIntelligence(
      baselines ?? [],
      measurements ?? [],
      targets ?? [],
      plans ?? [],
      childIds,
      homeId,
      periodStart ?? "2025-01-01",
      periodEnd ?? "2026-06-30",
      referenceDate ?? new Date().toISOString().slice(0, 10),
    );

    return NextResponse.json(result);
  } catch (error: any) {
    return NextResponse.json(
      { error: error.message || "Internal server error" },
      { status: 500 },
    );
  }
}

