function pocket_money_weeklyPocketMoney(childId: string, rate: number, startWeeksAgo: number): FinancialTransaction[] {
  const now = Date.now();
  const txns: FinancialTransaction[] = [];
  for (let w = 0; w < startWeeksAgo; w++) {
    const date = new Date(now - w * 7 * 24 * 60 * 60 * 1000);
    txns.push({
      id: `pm-${childId}-${w}`,
      date: date.toISOString(),
      type: "pocket_money",
      amount: rate,
      description: "Weekly pocket money",
      method: "cash",
      receiptRecorded: true,
      authorisedBy: "staff-rm-01",
      childSignature: true,
    });
  }
  return txns;
}
function pocket_money_monthlySavings(childId: string, amount: number, months: number): FinancialTransaction[] {
  const now = Date.now();
  const txns: FinancialTransaction[] = [];
  for (let m = 0; m < months; m++) {
    const date = new Date(now - m * 30 * 24 * 60 * 60 * 1000);
    txns.push({
      id: `sv-${childId}-${m}`,
      date: date.toISOString(),
      type: "savings_deposit",
      amount,
      description: "Monthly savings",
      method: "bank_transfer",
      receiptRecorded: true,
      authorisedBy: "staff-rm-01",
    });
  }
  return txns;
}
