async function post_positive_reinforcement_rewards(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const { praise, rewards, outcomes, training, homeId, periodStart, periodEnd } = body as {
    praise?: PraiseRecord[];
    rewards?: RewardRecord[];
    outcomes?: BehaviourOutcome[];
    training?: StaffReinforcementTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }

  const result = generatePositiveReinforcementRewardsIntelligence(
    praise ?? [],
    rewards ?? [],
    outcomes ?? [],
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

