async function get_recreational_leisure_access(req: NextRequest): Promise<Response> {

  const { activities, policy, training } = recreational_leisure_access_generateDemoData();

  const result = generateRecreationalLeisureAccessIntelligence(
    activities,
    policy,
    training,
    "oak-house",
    "2026-01-01",
    "2026-05-19",
  );

  return NextResponse.json({
    data: {
      ...result,
      meta: {
        activitySummary: activities.map((a) => ({
          id: a.id,
          childName: a.childName,
          date: a.activityDate,
          type: getActivityTypeLabel(a.activityType),
          participation: getParticipationLevelLabel(a.participationLevel),
          enjoyed: a.childEnjoyed,
        })),
        ratingLabel: getRatingLabel(result.rating),
      },
    },
  });
}

async function post_recreational_leisure_access(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    activities,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    activities?: LeisureActivity[];
    policy?: LeisurePolicy | null;
    training?: StaffLeisureTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateRecreationalLeisureAccessIntelligence(
    activities ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

