async function post_therapeutic_care(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const { sessions, referrals, plans, environments, homeId, periodStart, periodEnd } = body as {
    sessions?: TherapySession[];
    referrals?: TherapyReferral[];
    plans?: TherapyPlan[];
    environments?: TherapeuticEnvironment[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }

  const result = generateTherapeuticCareIntelligence(
    sessions ?? [],
    referrals ?? [],
    plans ?? [],
    environments ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

